function generateSelectRows(){const e=document.getElementById("stoixeiaSymbaseonContainer");e.innerHTML="";for(let n=1;n<=15;n++){const l=`\n      <div class="row form-group g-3 align-items-center d-none showhide_row_${n.toString().padStart(2,"0")}" style="background-color: #ffffff; margin-left: -1rem; margin-right: -1rem;">\n        <div class="col-2 left-align">\n          <label class="col-form-label label-font-size">\n            Στοιχείο Σύμβασης #${n}\n          </label>\n        </div>\n        <div class="col-9">\n        <label class="label-font-size-larger" style="margin-left: 0.8rem;" id="stoixeio_symbashs_${n.toString().padStart(2,"0")}"> </label>\n        </div>\n        <div class="col-1">\n        <label class="label-font-size-larger text-right" style="margin-left: 2rem;" id="checkSymbol_${n.toString().padStart(2,"0")}" ><i class="bi bi-check-lg" style="font-size: 24px; color: green;"></i></label>\n        </div>\n      </div>\n    `;e.insertAdjacentHTML("beforeend",l)}}document.addEventListener("DOMContentLoaded",(function(){generateSelectRows()}));